const rows = $input.all();
if (rows.length === 0 || !rows[0].json.feed_name) {
  return [{ json: { text: 'No monitored feeds or posts found.', post_ids: [], ref_map: {} } }];
}

const publications = {};
const postIds = new Set();

rows.forEach(row => {
  const data = row.json;
  const feedName = data.feed_name;
  if (!publications[feedName]) {
    publications[feedName] = [];
  }
  if (data.post_id) {
    postIds.add(data.post_id);
    publications[feedName].push({
      id: data.post_id,
      title: data.post_title,
      content: data.post_content,
      author: data.post_author,
      url: data.post_url,
      published_at: data.post_published_at
    });
  }
});

// Assign sequential numbers to every post for the LLM to reference
const refMap = {};
let refCounter = 1;

let text = 'Substack posts to summarize (each has an id number):\n\n';

for (const [feedName, posts] of Object.entries(publications)) {
  if (posts.length === 0) continue;

  text += `Publication: ${feedName}\n`;
  posts.forEach(post => {
    const refId = refCounter++;
    refMap[String(refId)] = { title: post.title || 'Post', url: post.url || '', feed_name: feedName };

    text += `  id:${refId} | ${post.title || 'No Title'} (by ${post.author || 'unknown'})\n`;
    text += `  Content: ${(post.content || '').substring(0, 500)}\n\n`;
  });
}

const fs = require('fs');
let persona = '';
try {
  persona = fs.readFileSync('/etc/n8n/agents/bella.md', 'utf8');
} catch (e) {
  persona = 'Warm, charming Italian secretary named Bella.';
}

let strategy = '';
try {
  strategy = fs.readFileSync('/etc/n8n/workflows/prompts/content_strategy.md', 'utf8');
} catch (e) {
  strategy = '';
}

let positioning = '';
try {
  positioning = fs.readFileSync('/etc/n8n/workflows/prompts/usp_market_positioning.md', 'utf8');
} catch (e) {
  positioning = '';
}

return [{ json: { text, post_ids: Array.from(postIds), ref_map: refMap, bella_persona: persona, content_strategy: strategy, usp_positioning: positioning } }];

